#include <batteries/async/toggle.hpp>
//

#include <batteries/int_types.hpp>
#include <batteries/optional.hpp>
#include <batteries/shared_ptr.hpp>

#include <benchmark/benchmark.h>

#include <chrono>
#include <memory>
#include <random>
#include <shared_mutex>
#include <thread>
#include <unordered_map>

namespace {

using namespace batt::int_types;

using batt::None;
using batt::Optional;

constexpr usize kNumWriterThreads = 1;
constexpr usize kNumRefresh = usize{1} << 10;
constexpr usize kMinOpCount = usize{1} << 24;
constexpr usize kMaxOpCount = usize{1} << 24;

struct SharedState : batt::RefCounted<SharedState> {
    std::unordered_map<u64, u64> map_;
};

class ReadScalabililty : public ::benchmark::Fixture
{
   public:
    void SetUp(::benchmark::State& state) override
    {
        this->n_ops = state.range(0);
        this->refresh_every_n = this->n_ops / kNumRefresh;
    }

    void TearDown(::benchmark::State& state [[maybe_unused]]) override
    {
    }

    //----- --- -- -  -  -   -

    template <typename Rng, typename Dist>
    void make_new_map(Rng& rng, Dist& pick_key, usize n_items, std::unordered_map<u64, u64>& map_out)
    {
        map_out.clear();
        for (usize item_i = 0; item_i < n_items; ++item_i) {
            map_out[pick_key(rng)] = item_i;
        }
    }

    template <typename Rng, typename Dist>
    SharedState* make_new_shared_state(Rng& rng, Dist& pick_key)
    {
        auto* new_state = new SharedState;
        intrusive_ptr_add_ref(new_state);
        this->make_new_map(rng, pick_key, this->refresh_every_n, new_state->map_);
        return new_state;
    }

    void reclamation_thread_main()
    {
        boost::intrusive_ptr<SharedState> to_delete = nullptr;

        while (this->stopping_.load() == false) {
            boost::intrusive_ptr<SharedState> expired = nullptr;

            // Remove the first item from the queue (if there is one).
            //
            {
                std::unique_lock<std::mutex> lock{this->queue_mutex_};
                if (!this->queue_.empty()) {
                    expired = std::move(this->queue_.front());
                    this->queue_.pop_front();
                }
            }

            // Hold `expired` for one period.
            //
            std::this_thread::sleep_for(std::chrono::microseconds(this->epoch_period_usec_));

            // Release `to_delete`, scheduling `expired` to be deleted on the next iteration of this loop.
            //
            to_delete = std::move(expired);
        }
    }

    void retire(boost::intrusive_ptr<SharedState>&& to_retire)
    {
        std::unique_lock<std::mutex> lock{this->queue_mutex_};
        this->queue_.emplace_back(std::move(to_retire));
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    // General parameters.
    //
    usize n_ops = 0;
    usize refresh_every_n = 0;

    // This must be set long enough to cover the period of time between when a thread loads the active state
    // pointer from the atomic variable (`this->active_state_`) and incrementing its ref count.
    //
    i64 epoch_period_usec_ = 150;

    // For the Toggle implementation.
    //
    batt::Toggle<std::unordered_map<u64, u64>> toggle;

    // For the EBR implementation.
    //
    std::atomic<bool> stopping_ = false;
    std::mutex queue_mutex_;
    std::deque<boost::intrusive_ptr<SharedState>> queue_;
    std::atomic<SharedState*> active_state_ = nullptr;
    Optional<std::thread> reclamation_thread_;
};

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
BENCHMARK_DEFINE_F(ReadScalabililty, Toggle)(benchmark::State& state)
{
    const bool is_writer = state.thread_index() < kNumWriterThreads;
    std::default_random_engine rng{/*seed=*/(u32)state.thread_index()};
    std::uniform_int_distribution<u64> pick_key{0, 9999};

    if (is_writer) {
        batt::Toggle<std::unordered_map<u64, u64>>::Writer writer{this->toggle};
        this->make_new_map(rng, pick_key, this->refresh_every_n, writer.new_value());
    }

    for (auto _ : state) {
        if (is_writer) {
            for (usize refresh_i = 0; refresh_i < kNumRefresh; ++refresh_i) {
                batt::Toggle<std::unordered_map<u64, u64>>::Writer writer{this->toggle};
                this->make_new_map(rng, pick_key, this->refresh_every_n, writer.new_value());
            }
        } else {
            for (usize op_i = 0; op_i < this->n_ops; ++op_i) {
                batt::Toggle<std::unordered_map<u64, u64>>::Reader reader{this->toggle};

                u64 key = pick_key(rng);
                auto iter = reader->find(key);

                benchmark::DoNotOptimize(iter);
            }
        }
    }
}

BENCHMARK_REGISTER_F(ReadScalabililty, Toggle)
    ->ThreadRange(1 + kNumWriterThreads, std::thread::hardware_concurrency())
    ->Range(kMinOpCount, kMaxOpCount);

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
BENCHMARK_DEFINE_F(ReadScalabililty, EBR)(benchmark::State& state)
{
    const bool is_writer = state.thread_index() < kNumWriterThreads;
    std::default_random_engine rng{/*seed=*/(u32)state.thread_index()};
    std::uniform_int_distribution<u64> pick_key{0, 9999};

    if (is_writer) {
        this->active_state_.store(this->make_new_shared_state(rng, pick_key));
        this->reclamation_thread_.emplace([this] {
            this->reclamation_thread_main();
        });
    }
    auto on_scope_exit = batt::finally([&] {
        if (is_writer) {
            this->stopping_.store(true);
            this->reclamation_thread_->join();
        }
    });

    for (auto _ : state) {
        if (is_writer) {
            for (usize refresh_i = 0; refresh_i < kNumRefresh; ++refresh_i) {
                SharedState* next_state = this->make_new_shared_state(rng, pick_key);
                boost::intrusive_ptr<SharedState> prev_state{this->active_state_.exchange(next_state),
                                                             /*add_ref_count=*/false};
                this->retire(std::move(prev_state));
            }
        } else {
            for (usize op_i = 0; op_i < this->n_ops; ++op_i) {
                boost::intrusive_ptr<const SharedState> observed_state{this->active_state_.load()};

                u64 key = pick_key(rng);
                auto iter = observed_state->map_.find(key);

                benchmark::DoNotOptimize(iter);
            }
        }
    }
}

BENCHMARK_REGISTER_F(ReadScalabililty, EBR)
    ->ThreadRange(1 + kNumWriterThreads, std::thread::hardware_concurrency())
    ->Range(kMinOpCount, kMaxOpCount);

}  //namespace
